bool canFinish(int n, int** prereq, int pc, int* pcCol) {
    int* indeg = calloc(n, sizeof(int));
    int** adj = calloc(n, sizeof(int*));
    int* deg = calloc(n, sizeof(int));
    for (int i = 0; i < pc; i++) {
        int a = prereq[i][0], b = prereq[i][1];
        adj[b] = realloc(adj[b], (deg[b]+1)*sizeof(int));
        adj[b][deg[b]++] = a;
        indeg[a]++;
    }
    int* q = malloc(n*sizeof(int)), h=0, t=0, seen=0;
    for (int i=0;i<n;i++) if (!indeg[i]) q[t++]=i;
    while (h<t) {
        int u=q[h++]; seen++;
        for (int j=0;j<deg[u];j++) if (--indeg[adj[u][j]]==0) q[t++]=adj[u][j];
    }
    free(indeg); free(deg); free(q);
    return seen==n;
}
